@* Displays a single task card with move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="text-muted small">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeftClicked { get; set; }
    [Parameter] public EventCallback<int> OnMoveRightClicked { get; set; }

    private bool IsMoving;

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async System.Threading.Tasks.Task OnMoveLeft()
    {
        IsMoving = true;
        await OnMoveLeftClicked.InvokeAsync(Task.Id);
        IsMoving = false;
    }

    private async System.Threading.Tasks.Task OnMoveRight()
    {
        IsMoving = true;
        await OnMoveRightClicked.InvokeAsync(Task.Id);
        IsMoving = false;
    }
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="Priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="DueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@IsSaving">Save</button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="HandleCancel" disabled="@IsSaving">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }

    private string Title { get; set; } = "";
    private string Assignee { get; set; } = "";
    private string Priority { get; set; } = "Medium";
    private DateTime DueDate { get; set; } = DateTime.Today.AddDays(7);
    private bool IsSaving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(Title)) return;
        IsSaving = true;
        await OnSave.InvokeAsync((Title, Assignee, Priority, DueDate));
        IsSaving = false;
    }

    private async Task HandleCancel() => await OnCancel.InvokeAsync();
}

@* A single Kanban column: header with count, task cards, and add-task form toggle *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary rounded-pill">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowLeft"
                          ShowMoveRight="ShowRight"
                          OnMoveLeftClicked="OnMoveLeft"
                          OnMoveRightClicked="OnMoveRight" />
            }

            @if (ShowAddForm)
            {
                <AddTaskForm OnSave="HandleSave" OnCancel="HandleCancel" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => ShowAddForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowLeft { get; set; }
    [Parameter] public bool ShowRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnTaskCreated { get; set; }

    private bool ShowAddForm;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        await OnTaskCreated.InvokeAsync((args.Title, args.Assignee, args.Priority, args.DueDate, ColumnName));
        ShowAddForm = false;
    }

    private void HandleCancel() => ShowAddForm = false;
}

@* Search input for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await SearchTermChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummary Tasks="allTasks" />
    <BoardSearchBar @bind-SearchTerm="searchTerm" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     ShowLeft="false"
                     ShowRight="true"
                     OnMoveRight="HandleMoveRight"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     ShowLeft="true"
                     ShowRight="true"
                     OnMoveLeft="HandleMoveLeft"
                     OnMoveRight="HandleMoveRight"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetFilteredTasks("Done")"
                     ShowLeft="true"
                     ShowRight="false"
                     OnMoveLeft="HandleMoveLeft"
                     OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] Statuses = { "To Do", "In Progress", "Done" };

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task HandleMoveLeft(int taskId)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == taskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Statuses, task.Status);
        if (currentIndex <= 0) return;

        var newStatus = Statuses[currentIndex - 1];
        await MoveTask(taskId, newStatus);
    }

    private async Task HandleMoveRight(int taskId)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == taskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Statuses, task.Status);
        if (currentIndex < 0 || currentIndex >= Statuses.Length - 1) return;

        var newStatus = Statuses[currentIndex + 1];
        await MoveTask(taskId, newStatus);
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            // Update locally to avoid a full reload
            var index = allTasks.FindIndex(t => t.Id == taskId);
            if (index >= 0)
            {
                var old = allTasks[index];
                allTasks[index] = old with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            // The service creates tasks — we add the returned item with the correct status
            allTasks.Add(created with { Status = args.Status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

