@* Search input for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await SearchTermChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummary Tasks="allTasks" />
    <BoardSearchBar @bind-SearchTerm="searchTerm" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     ShowLeft="false"
                     ShowRight="true"
                     OnMoveRight="HandleMoveRight"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     ShowLeft="true"
                     ShowRight="true"
                     OnMoveLeft="HandleMoveLeft"
                     OnMoveRight="HandleMoveRight"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetFilteredTasks("Done")"
                     ShowLeft="true"
                     ShowRight="false"
                     OnMoveLeft="HandleMoveLeft"
                     OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] Statuses = { "To Do", "In Progress", "Done" };

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task HandleMoveLeft(int taskId)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == taskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Statuses, task.Status);
        if (currentIndex <= 0) return;

        var newStatus = Statuses[currentIndex - 1];
        await MoveTask(taskId, newStatus);
    }

    private async Task HandleMoveRight(int taskId)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == taskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Statuses, task.Status);
        if (currentIndex < 0 || currentIndex >= Statuses.Length - 1) return;

        var newStatus = Statuses[currentIndex + 1];
        await MoveTask(taskId, newStatus);
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var index = allTasks.FindIndex(t => t.Id == taskId);
            if (index >= 0)
            {
                var old = allTasks[index];
                allTasks[index] = old with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            allTasks.Add(created with { Status = args.Status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

